    let run_id = parse_run_id(&args.run_id)?;
    let discarded = discard_run(state, run_id)?;
    if args.json {
        write_json(&discarded)
    } else {
        write_human_stdout(&format!("Discarded run {run_id}; receipt preserved.\n"))
            .map_err(CliError::Output)
    }
}

